INSERT INTO public.photos VALUES (22688, 'Glorieta de Sasera c.1971', 'Apoteosis del baturrismo costumbrista, en la glorieta de Sasera. Al fondo, paseo del General Mola. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64580900, -0.88525800, '0101000020E61000003DB7D0950854ECBF323B8BDEA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26812122123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26812122123.webp', 'https://www.flickr.com/photos/zaragozaantigua/26812122123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23786, 'Conservas Marraco 1908', 'Imagen capturada en el interior de la f├íbrica de conservas vegetales de Marraco Hermanos, sita en Monzalbarba. Ubicada cerca de la estaci├│n ferroviaria Utebo-Monzalbarba, contaba con cultivos propios. Empez├│ su actividad en 1895, y entre sus especialidades estaban los guisantes al estilo franc├®s y el pur├® de tomate concentrado por evaporaci├│n al vac├¡o.', 1908, 1908, 1908, 'Anos 1900', NULL, 41.70046300, -0.98148100, '0101000020E6100000ECA694D74A68EFBF6E8786C5A8D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53818476910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53818476910.webp', 'https://www.flickr.com/photos/zaragozaantigua/53818476910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22717, 'P.┬║ de Sagasta 1979', 'Imagen capturada en el arranque del paseo de Sagasta durante el derribo del antiguo colegio del Sagrado Coraz├│n de Jes├║s, en esa ubicaci├│n desde 1875. Teodoro R├¡os Balaguer proyecto buena parte de su f├íbrica, luego ampliada. Como en otros casos en la ciudad, a comienzos de los a├▒os setenta del pasado siglo, y dentro de la no oficial "Operaci├│n Colegios Privados", este inmenso colegio fue desalojado, derribado, y sobre su solar se construyeron nuevos referentes de la Zaragoza postmoderna: un complejo residencial, y una gran superficie comercial. El colegio de nueva planta, de esta franquicia, llevaba funcionando desde 1975 en el entonces despoblado norte de la ciudad, junto a la avenida de los Pirineos. En la imagen, derribo del colegio en su parte delimitada entre el paseo de Sagasta, desde donde se ha hecho la foto; la glorieta de Sasera, a la izquierda, de donde emerge la gr├║a; y el paseo de las Damas, al fondo, donde aparecen las fachadas de los n├║meros 5, y 7, de esa calle. En primer plano, un pedazo de muro por donde algo m├ís tarde se abrir├¡a la conexi├│n con la calle Le├│n XIII, y en ese muro, un recuerdo del paso por Zaragoza de la "ballena gigante Jon├ís", tra├¡da desde el Atl├íntico norte por Adena-WWF durante la campa├▒a "Los mares deben vivir". Fuente visual: Gerardo Sancho Ramo, en AMZ/ES. 50297. AM 04.01.02.11 Carpeta conservaci├│n 25081', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64497900, -0.88548100, '0101000020E61000000C570740DC55ECBFABCDFFAB8ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30099935246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30099935246.webp', 'https://www.flickr.com/photos/zaragozaantigua/30099935246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22906, 'Sala En Bruto 1989', 'Posado del grupo vallisoletano The Bumpers en la puerta de la sala de conciertos En Bruto, inaugurada en 1986 en la calle Comandante Santa Pau 1 de Zaragoza. Tras un concierto all├¡ de H├®roes del silencio en 1987, este grupo firm├│ su contrato con una multinacional. Desde 2009, la calle se denomina H├®roes del silencio. Fuente visual: www.valladolidwebmusical.org/bandas/especiales/bumpers/', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64288300, -0.88474300, '0101000020E61000007DAD4B8DD04FECBFC2137AFD49D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21921962503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21921962503.webp', 'https://www.flickr.com/photos/zaragozaantigua/21921962503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23188, 'Gran V├¡a 2010', '30 de enero de 2010. Acera de los impares en la Gran V├¡a de Zaragoza, a la altura de su confluencia con la calle Arzobispo Dom├®nech, a la derecha. El r├¡o Huerva, descubierto por las obras de reforzamiento del firme realizadas ese a├▒o. Fuente: www.facebook.com/photo.php?fbid=10203907260380622&set...', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.64593900, -0.88806600, '0101000020E6100000AE105663096BECBF001B1021AED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15371332315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15371332315.webp', 'https://www.flickr.com/photos/zaragozaantigua/15371332315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24002, 'Calle Royo c.1962', 'Imagen del portal 5-7 de la calle de Mariano Royo Urieta de Zaragoza, con la entrada de la sala de fiestas Cancela a la izquierda. Este negocio fue abierto en 1962 y cerrado en 1979. Contaba con tres plantas, entre las que se repart├¡an el sal├│n de espect├ículos, las barras de alterne y los reservados. All├¡ actuaron Estrellita Castro, Antonio Mach├¡n, Luis Mariano y Josephine Baker.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64556100, -0.88723200, '0101000020E610000098DEFE5C3464ECBF5A492BBEA1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21956341134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21956341134.webp', 'https://www.flickr.com/photos/zaragozaantigua/21956341134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24236, 'P.┬║ del General Mola c.1954', 'Gigantes y Cabezudos durante una pausa procesionaria en el paseo del General Mola, a la altura del emboque a la calle de Mariano de La Gasca, a la izquierda (fuera de plano), junto al hotelito que fuera antigua cl├¡nica del doctor Lozano, en la solanera del lado de los edificios (sin) pares de ese tramo del paseo, algunos desaparecidos a├▒os despu├®s. Fuente visual: "Zaragoza y sus fiestas".', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64508600, -0.88595700, '0101000020E61000005531957EC259ECBFC18D942D92D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32254938842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32254938842.webp', 'https://www.flickr.com/photos/zaragozaantigua/32254938842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24257, 'Encauzamiento Huerva 1925', 'Comienzo de las obras de encauzamiento del r├¡o Huerva en el tramo denominado "entre la Veneciana y la Facultad". 1925. A la izquierda, los edificios de la Facultad de Medicina y Ciencias. Al fondo, el puente de Santa Engracia. A la derecha, andamios del nuevo cauce sobre el que cubrir el r├¡o. En el Plan de Ensanche de 1934 este tramo ser├¡a denominado "Gran V├¡a de Pablo Iglesias", uno de los tres nuevos tramos urbanos resultantes del cubrimiento del Huerva. Los otros dos ser├¡an "Gran V├¡a de Francisco Giner de los R├¡os", y "Gran V├¡a de Gal├ín y Garc├¡a Hern├índez". Estas denominaciones, tras el 18 de julio de 1936, tuvieron ef├¡mera vida, como la de quienes las propusieron.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64576200, -0.88905500, '0101000020E6100000890CAB782373ECBFF17F4754A8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978040218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978040218.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978040218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25079, 'Tina Turner 1990', 'Actuaci├│n de la cantante estadounidense Tina Turner (1939) en La Romareda, el 9 de octubre de 1990, con El ├║ltimo de la fila como teloneros. Fuente: Agencia EFE.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24519754352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24519754352.webp', 'https://www.flickr.com/photos/zaragozaantigua/24519754352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25081, 'James Brown 1988', 'EL 12 de octubre de 1988, el cantante estadounidense James Brown (1933-2006) actu├│ en La Romareda, con el grupo espa├▒ol La Uni├│n como teloneros. Fuente: Agencia EFE.', 1988, 1988, 1988, 'Anos 80', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24627468385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24627468385.webp', 'https://www.flickr.com/photos/zaragozaantigua/24627468385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25596, 'Feria de Muestras 1955', 'Vista del entorno del recinto de la Feria de Muestras, desde las alturas de la "Residencia Sanitaria Jos├® Antonio". A la izquierda, el Campus de San francisco, con la Facultad de Filosof├¡a y Letras. Al fondo, el nov├¡simo edificio de Regino Borobio Ojeda para la ÔÇ£Escuela de Maestr├¡a Industrial de ZaragozaÔÇØ y la "Escuela T├®cnica de Peritos Industriales" (actual CPIFP Corona de Arag├│n). En el centro, imagen del Paseo de Fernando el Cat├│lico ya casi totalmente construido en lo que a viviendas se refiere. Aparcamientos en superficie, y en bater├¡a, una rareza que nunca m├ís se volver├í a ver en esa ubicaci├│n. A la derecha, el Puente 13 de setiembre, y el acceso al Parque Primo de Rivera, donde est├í en obras la "Casa Ansotana", cuya primera piedra se hab├¡a puesto en abril de este a├▒o, y ser├í inaugurada en marzo del a├▒o siguiente. M├ís adelante, la significada torre del complejo de la Editorial Luis Vives. Al fondo, el skyline de la ciudad hist├│rica, con La Casa de Misericordia, San Pablo, Santiago el Mayor, y la bas├¡lica del Pilar, con las dos torres ribere├▒as en ascenso.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63753600, -0.89840000, '0101000020E6100000AB3E575BB1BFECBFE60297C79AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14804299308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14804299308.webp', 'https://www.flickr.com/photos/zaragozaantigua/14804299308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24261, 'Camino del S├íbado 1930', 'Imagen del nov├¡simo n┬║ 17 de la Gran V├¡a, dise├▒ado en 1930 por Jos├® y Regino Borobio para Isidoro Mart├¡nez Ortiz, como primer y, de momento, aislado edificio construido en el eje de desarrollo de este nuevo vial de la ciudad, tras el recubrimiento del urbano tramo del r├¡o Huerva que por aqu├¡ fluye. La imagen est├í capturada desde las traseras del edificio, en el antiguo Camino del S├íbado, junto a una acequia que desaguaba en el Huerva, y cuyo sinuoso recorrido explica el irregular trazado de los muros que delimitaban esta propiedad, y los de las huertas de la zona. La fachada principal, y ├®sta trasera, son dispares en altura: desde este trasero y sabatino punto de vista, se trataba de un enorme edifico de ocho plantas de altura (7+bajos), adem├ís de un pl├ístico ├ítico. Desde la Gran V├¡a, el edificio parece "encoger" al menos dos pisos, como consecuencia de la importante diferencia de altura que el recubrimiento del r├¡o hab├¡a establecido entre ambos puntos: los muros del fondo, a ambos lados del edifico, indican el horizonte establecido por la "caja" que cubr├¡a el r├¡o, a la que se sumaba el murete de protecci├│n para evitar ca├¡das, hasta que los solares de sus medianeras fueron construidos. A├▒os despu├®s, el remate del edificio ser├¡a modificado y convertido en una nueva planta completa, perdiendo con ello su caracter├¡stica y art├¡stica veleta. El tranquilo riego con manguera del patio trasero, tal que si fuera un adosado de las Adulas, "avant la lettre ". Fuente visual: foto Miguel Mar├¡n Chivite, en "Una mirada a trav├®s de la arquitectura: Regino y Jos├® Borobio Ojeda", de Daniel Estab├®n Boldova.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64576400, -0.88802400, '0101000020E6100000F304C24EB16AECBF92770E65A8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24647321235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24647321235.webp', 'https://www.flickr.com/photos/zaragozaantigua/24647321235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24543, 'P┬║ de Sagasta c.1914', 'Imagen capturada en el interior de la f├íbrica de camas de hierro de la Viuda de Irisarri, sita en el n┬║ 10 del paseo de Sagasta Esta fue la tercera de las ubicaciones urbanas de esta f├íbrica, fundada originalmente en 1860 por Miguel Irisarri en la calle Don Jaime I. En 1887 comenzaron las gestiones para construir esta f├íbrica en el entonces camino de Torrero, en un solar de los Campos El├¡seos, donde perdur├│ hasta que en 1927 se traslad├│ a la calle del Castillo. En la imagen, una de las camas producidas en esta factor├¡a, que en la d├®cada de los a├▒os 10 conoci├│ la introducci├│n de mejoras como dorarlas al fuego y barnizarlas con esmalte, que redundaban en la perdurabilidad del producto. Esta f├íbrica conoci├│ a principios de esta misma d├®cada un importante conflicto protagonizado por sus obreros metal├║rgicos.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53455093699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53455093699.webp', 'https://www.flickr.com/photos/zaragozaantigua/53455093699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24901, 'P.┬║ del General Mola 1947', 'Gran edificio administrativo situado en el paseo del General Mola n┬║ 24, para albergar las oficinas de la Confederaci├│n Hidrogr├ífica del Ebro. Proyecto racionalista ejemplar, firmado por los hermanos Borobio. Fuente visual: "Regino y Jos├® Borobio Ojeda", Ayuntamiento de Zaragoza, 1991.', 1947, 1947, 1947, 'Anos 40', 'CENTRO', 41.64471200, -0.88597600, '0101000020E6100000054F2157EA59ECBF5CAB3DEC85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15533616425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15533616425.webp', 'https://www.flickr.com/photos/zaragozaantigua/15533616425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24927, 'Glorieta de Sasera 1963', 'Imagen capturada en la glorieta de Sasera. y centrada en el decimom├│nico grupo escult├│rico instalado ese a├▒o en bronce como homenaje a los defensores del Reducto del Pilar durante el asedio franc├®s en 1809, que culmin├│ con la toma del reducto y la capitulaci├│n de la ciudad. Originalmente realizado en yeso por el escultor Federico Amutio y Amil en 1892, fue adquirido por el Ayuntamiento en una versi├│n en bronce que primero estuvo en la Casa Consistorial de la plaza de Santo Domingo, y que en 1963 fue ubicado en esta localizaci├│n para sustituir al obelisco realizado por Ricardo Magdalena que desde 1908 fue el original monumento a los defensores del Reducto del Pilar. De esta forma, el obelisco fue retirado y demolido, y en su lugar se emplaz├│ esta escultura que en principio estaba dedicada a dos combatientes an├│nimos de la guerra contra Francia, sin especificar su ubicaci├│n. Presenta la inscripci├│n en el pedestal que reza "Por la Virgen del Pilar. Vencer o morir. MDCCCVIII", y el acompa├▒amiento de un par de ca├▒ones de ├®poca. Tras el monumento, muro perimetral del tradicional colegio del Sagrado Coraz├│n recayente a la glorieta, adem├ís de modernos inmuebles en el arranque del paseo del General Mola.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64581100, -0.88527900, '0101000020E61000001BBD1AA03454ECBFD33252EFA9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50343761923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50343761923.webp', 'https://www.flickr.com/photos/zaragozaantigua/50343761923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25019, 'Obelisco Reducto del Pilar 1909', 'AHPZ. Archivo Coyne. 1909. Con posterioridad a la Exposici├│n Hispano-Francesa de 1908, en la Glorieta Sasera se instal├│ un peque├▒o obelisco dise├▒ado por Ricardo Magdalena con el que recordar a los defensores del reducto del Pilar, con la incalificable inscripci├│n "Morir por la Virgen del Pilar o vencer. A los heroicos defensores del reducto del Pilar. Primer centenario de Los Sitios. 1908." En la imagen, aspecto de la institucional ceremonia de inauguraci├│n del obelisco en la Glorieta de P├®rez Gald├│s (luego redenominada de Sasera), a finales del mes de enero. Hay autoridades (con sombrero de copa), funcionarios municipales (disfrazados de maceros, para dar ambiente), y p├║blico en general. El muro del fondo protege al colegio de los PP. Jesuitas.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.64588300, -0.88527900, '0101000020E61000001BBD1AA03454ECBF6C054D4BACD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15043782215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15043782215.webp', 'https://www.flickr.com/photos/zaragozaantigua/15043782215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25024, 'Avenida de la Rep├║blica 1936', '"Sanatorio Lozano : Vista del porche y jard├¡n". En 1903 el arquitecto F├®lix Navarro proyect├│ un nuevo edificio para vivienda y cl├¡nica del doctor Lozano en el ensanche burgu├®s del paseo de Sagasta (esquina con Lagasca). Pocos a├▒os despu├®s fue objeto de la primera de las bastantes reformas que desvirtuaron un tanto el proyecto de Navarro aunque, al menos, supervive, lo que no es poco, trat├índose de Zaragoza. Se trat├│ de la reforma de Manuel del Busto, que en 1916 ampli├│ y reform├│ su aspecto, dej├índolo como la imagen muestra. En 2009 el edificio fue declarado "bien del patrimonio cultural aragon├®s", cuando ya una promotora inmobiliaria ten├¡a fumata blanca de la comisi├│n provincial de Patrimonio para levantar en sus jardines un bloque de viviendas de doce alturas. En 2013, el Tribunal Superior de Justicia de Arag├│n anul├│ el proyecto por cuestiones vinculadas a la iluminaci├│n, ventilaci├│n, dimensiones de los patios y distancias respecto a otros edificios. El Ayuntamiento recurri├│ al Tribunal Supremo, que a├║n no se ha pronunciado. Hace poco, el Ayuntamiento requiri├│ a la propiedad del inmueble la realizaci├│n de una serie de actuaciones relacionadas con la seguridad del edificio, para evitar afecciones a la v├¡a p├║blica. De resultas de ello, el edificio se encuentra rodeado de andamios y malla pl├ística de obra. En la imagen, aspecto del "Sanatorio Lozano" capturado desde la Avenida de la Rep├║blica. A la izquierda, la calle de La Gasca. Siquiera parcialmente, a├║n es visible el remate en forma de torrecilla bulbosa que, dise├▒ada por Navarro, posteriores reformas han eliminado. Y abajo, a al derecha, un pedacito de los antiguos y p├®treos bancos de la Avenida. Fuente visual: www.bancodeimagenesmedicina.es/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64496900, -0.88607300, '0101000020E6100000A3CB9BC3B55AECBF88F71C588ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17176022199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17176022199.webp', 'https://www.flickr.com/photos/zaragozaantigua/17176022199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25031, 'P.┬║ del General Mola 1938', 'Imagen capturada por un soldado alem├ín de la Legi├│n C├│ndor, centrada en el edificio de la Confederaci├│n Hidrogr├ífica del Ebro, dise├▒ada por Regino y Jos├® Borobio, cuya construcci├│n se hab├¡a iniciado en 1936, cuando esta era la avenida de la Rep├║blica. Ahora, tras el golpe del 18-19 de julio de ese a├▒o, hab├¡a sido redenominada "paseo del General Mola". Esta manzana, delimitada por las calles de Mariano Lagasca (inmediata, a la derecha), y Cervantes, se completaba con el edificio del n┬║ 30, realizado la anterior d├®cada con proyecto de Teodoro R├¡os Balaguer. A continuaci├│n, y esquinera con la calle de Cervantes, la desaparecida casa de los Escoriaza-Averly, dise├▒ada por Luis de La Figuera. Entre los adoquines de la calzada, las v├¡as de la l├¡nea del tranv├¡a de Torrero. Fuente visual: www.ebay.es/', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64471200, -0.88597600, '0101000020E6100000054F2157EA59ECBF5CAB3DEC85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31033523395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31033523395.webp', 'https://www.flickr.com/photos/zaragozaantigua/31033523395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25034, 'P.┬║ de Sagasta 1899', 'Imagen de la fachada y el acceso desde el paseo de Sagasta a la f├íbrica de camas de hierro y lat├│n de Miguel Irisarri L├│pez de Goicoechea. Fundada en 1860 en la calle Don Jaime I, desde 1887 estaba en esta ubicaci├│n del antiguo camino de Torrero, entre el terreno denominado Campos El├¡seos y el Huerto y torre de Val (a la izquierda de la imagen), en unas instalaciones mucho m├ís amplias y modernas. Miguel Irisarri muri├│ en 1902, si bien la f├íbrica continu├│ aqu├¡ hasta que en 1927 fue trasladada al barrio del Castillo. Al fondo, a la derecha, el torre├│n sureste del reciente edificio de las Facultades de Medicina y Ciencias. Fuente visual: posiblemente foto Coyne, en "Arag├│n Ilustrado" n┬║ 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64582700, -0.88585800, '0101000020E61000008ACC5CE0F258ECBFD8EF8975AAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31631442273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31631442273.webp', 'https://www.flickr.com/photos/zaragozaantigua/31631442273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25052, '&quot;Las francesas&quot; c.1935', 'Abanderado posado colectivo de alumnas capturado en el patio de recreo del colegio de las religiosas del Sagrado Coraz├│n de Jes├║s, popularmente denominadas "las francesas", sito en la avenida de la Rep├║blica (antiguo paseo de Sagasta) desde 1875.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64471400, -0.88485900, '0101000020E6100000CB4752D2C350ECBFFDA204FD85D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52386103204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52386103204.webp', 'https://www.flickr.com/photos/zaragozaantigua/52386103204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20910, 'Campo del Toro 1777', 'Plano del Campo del Toro y sus inmediaciones, en el que se demuestra el terreno sobre el que se han hecho y levantado planos para quarteles y el terreno que la Misericordia ha ocupado del uno. 12 de enero de 1777. Archivo General de Simancas. Croquis del entorno de la plaza de toros de Zaragoza poco despu├®s de su construcci├│n, en 1764.Todos los elementos representados exist├¡an previamente, excepto los dos cuarteles proyectados junto a la plaza, en color marr├│n claro, que no llegaron a levantarse.', 1777, 1777, 1777, 'Siglo XIX', 'CENTRO', 41.65430000, -0.89160400, '0101000020E6100000F7729F1C0588ECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15457421447.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15457421447.webp', 'https://www.flickr.com/photos/zaragozaantigua/15457421447/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20994, 'Plaza de Toros 1816', '"Temeridad de Martincho en la plaza de Zaragoza". Tauromaquia, 18. Aguafuerte sobre papel. Francisco de Goya y Lucientes, 1816. Una de las estampas de la serie grabada por Goya entre la primavera de 1814 y el oto├▒o de 1816. Representa un lance del torero Martincho (Francisco Antonio Ebass├║n Mart├¡nez, 1708-1772) realizado en la plaza de Toros de Zaragoza muchas d├®cadas antes. A la izquierda, junto al toril, unos cuantos zaragozanos grotescos observan la audaz acrobacia. Fuente: Museo del Prado.', 1816, 1816, 1816, 'Siglo XIX', 'CENTRO', 41.65448600, -0.89193500, '0101000020E61000005F0CE544BB8AECBF4DD87E32C6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31371413243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31371413243.webp', 'https://www.flickr.com/photos/zaragozaantigua/31371413243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21368, 'Plaza de Toros c.1915', 'Puerta Principal de la Misericordia de Zaragoza, Luis Gand├║ Mercadal, entre 1912 y 1916. La puerta principal de la plaza coincide en su ubicaci├│n con la actual Puerta Grande. En la cubierta, la buhardilla alineada. Fuente visual: El coso de la Misericordia de Zaragoza (2014).', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65428400, -0.89152200, '0101000020E6100000AF4335255987ECBFE525FF93BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023574983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023574983.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023574983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21467, 'Coso de la Misericordia 1913', 'Imagen interior del Coso de la Misericordia centrada en la umbr├¡a Puerta de Arrastres, donde destaca el "balc├│n" sobre ├®l habilitado. La pervivencia del t├®rmino "balc├│n" recuerda la original celebraci├│n de este tipo de espect├ículos en la plaza del Mercado, cuando se utilizaban los balcones de las casas para acoger al p├║blico asistente de m├ís poder de adquisici├│n y estatus social. La estructura y aspecto de este coso apenas hab├¡a variado en lo fundamental desde su construcci├│n finalizada en 1765, conservando por ejemplo las arquer├¡as dieciochescas de madera que se elevan desde la grada cubierta hasta los palcos. S├¡ hab├¡a cambiado el firme del tendido o gradas, donde la piedra de siller├¡a sustituy├│ a la original madera, adem├ís de la introducci├│n de las barandillas de hierro, seg├║n reforma acometida entre 1877 y 1892. La escena muestra la plaza atestada de p├║blico, destacando los muy distintos perfiles sociales entre quienes de sientan sobre el p├®treo tendido y quienes ocupan el balc├│n, que aparece decorado con motivos vegetales, adem├ís de con los mantones de Manila de las "mujeres bonitas y requetepreciosas" que lo ocupan. Decorando la parte superior de los pilares que sustentan el palco presidencial, destacan banderas que flanquean cuatro escudos donde aparecen los cuatro cuarteles del escudo de la provincia de Zaragoza (de izquierda a derecha: el ├ürbol de Sobrarbe, la Cruz de Alcoraz cantonada con cuatro cabezas de moros, la Cruz de ├ì├▒igo Arista, y la Se├▒al Real de Arag├│n con las cuatro barras).', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65433200, -0.89180200, '0101000020E61000008E3C1059A489ECBFF65CA626C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459232719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459232719.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459232719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21705, 'Vista 1938', 'Los pilotos alemanes de la Legi├│n C├│ndor estacionados en el Aer├│dromo de Sanjurjo (base a├®rea de Zaragoza), durante su estancia colaboradora con los nacionalistas en la guerra desatada en julio de 1936, de permiso por la ciudad han dejado un apreciable cat├ílogo de instant├íneas por diferentes localizaciones. En esta ocasi├│n, se han subido al tejado de la "Santa y Real Hermandad de Nuestra Se├▒ora del Refugio y Piedad", vulgo "El Refugio", inaugurada en 1932, para tomar unas despejadas im├ígenes a unas trabajadoras, y uno de ellos les ha capturado desde atr├ís. A la izquierda, las dos torrecillas del Convento-noviciado de las Hermanas de la Caridad de Santa Ana. Al fondo, el Pilar. A la derecha, la c├║pula de la iglesia de Santiago, y el Hospital de Nuestra Se├▒ora de Gracia.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65119000, -0.89209100, '0101000020E61000003ACAC16C028CECBFBABDA4315AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15811810008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15811810008.webp', 'https://www.flickr.com/photos/zaragozaantigua/15811810008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21979, 'Calle de Pignatelli 1948', 'A la sombra del coso de la Misericordia, una despejada visual de la calle Pignatelli en direcci├│n al este, con la torre de la iglesia parroquial de Santiago el Mayor al fondo, y su antiguo remate. A la izquierda, el ingreso al cuartel del Parque de Artiller├¡a. A la derecha, el muro perimetral del hospicio del Hogar Pignatelli. En el suelo perduran los ra├¡les de la antigua l├¡nea de Madrid, clausurada en 1942. Fuente visual: foto Juan Mora Insa, AMZ.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.65457500, -0.89077100, '0101000020E6100000F834272F3281ECBFBDE3141DC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25240522930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25240522930.webp', 'https://www.flickr.com/photos/zaragozaantigua/25240522930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22444, 'Vista a├®rea Plaza de Toros 1960', 'Vista a├®rea centrada en la Plaza de Toros, con el barrio de San Pablo abajo. A la izquierda de la Plaza, el Hogar Pignatelli; a su derecha, el cuartel del Cid. Al fondo, la estaci├│n de Campo Sepulcro. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65453800, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFA0FEB3E6C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30984031580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30984031580.webp', 'https://www.flickr.com/photos/zaragozaantigua/30984031580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22515, 'Hogar Pignatelli c.1961', 'Imagen del gran patio occidental del Hogar Pignatelli, que vertebraba la zona ocupada por las ni├▒as y chicas residentes. En el momento de capturar la imagen, desde la altura del primer piso, un grupo de ni├▒as juega con aros entre la zona ajardinada que lo caracterizaba (a diferencia del oriental patio de los ni├▒os y chicos, totalmente despejado), bajo la atenta vigilancia de varias hermanas de la caridad de Santa Ana.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65348300, -0.89126500, '0101000020E6100000DA38622D3E85ECBFF9BEB854A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51407329330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51407329330.webp', 'https://www.flickr.com/photos/zaragozaantigua/51407329330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22796, 'P.┬║ de Mar├¡a Agust├¡n 1975', 'Imagen centrada en los bajos comerciales ocupados por Sala Rono, referencial establecimiento musical creado y dirigido por el casbasino Mariano Gracia Escario, en su moderna ubicaci├│n del paseo de Mar├¡a Agust├¡n n┬║ 22, local, en uno de los bloques para funcionarios all├¡ construidos inmediato a los Talleres del Hogar Pignatelli. Esta tienda de instrumentos musicales especializada en pianos, armon├¡a y ├│rganos, tuvo una primera ubicaci├│n localizada desde 1938 en el n┬║ 13 de la calle del Doctor G├│mez Ulla (antigua de la Biblioteca), desaparecida durante el proceso de ensanchamiento de la V├¡a Imperial, actual avenida de C├®sar Augusto. En 2015 este comercio fue finalmente clausurado. Fuente visual: Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65168900, -0.89066300, '0101000020E6100000603B18B14F80ECBFDB148F8B6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45190436582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45190436582.webp', 'https://www.flickr.com/photos/zaragozaantigua/45190436582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23100, 'B. B. King 2004', 'El guitarrista y cantante de blues B. B. King (1925-2015), actuando en la plaza de Toros de Zaragoza, el 1 de julio de 2004. Fuente: Agencia EFE.', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24049053564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24049053564.webp', 'https://www.flickr.com/photos/zaragozaantigua/24049053564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23114, 'Marcelino Iglesias 2003', 'Foto: Jos├® Miguel Marco. A la derecha, Marcelino Iglesias (PSOE), saludando a su socio Jos├® ├üngel Biel (PAR) durante la campa├▒a de las elecciones a Cortes de Arag├│n de mayo de 2003. Esta pareja gobern├│ Arag├│n, como presidente y vicepresidente, entre los a├▒os 1999 y 2011. La instant├ínea est├í tomada ante el Edificio Pignatelli, sede del Gobierno de Arag├│n. Fuente visual: Heraldo de Arag├│n.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65284600, -0.89175000, '0101000020E6100000F0A7C64B3789ECBF86A92D7590D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30983592134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30983592134.webp', 'https://www.flickr.com/photos/zaragozaantigua/30983592134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23916, 'Cuartel del Cid 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 04/04/1970. Vista de la puerta principal de acceso al abandonado Cuartel de Caballer├¡a de El Cid. En la actualidad justo aqu├¡ est├í el bloque de viviendas del n┬║ 6 de la calle Benjam├¡n Jarn├®s. Fue creado por Ram├│n Pignatelli junto al Coso de la Maestranza y a la Real Casa de la Misericordia. Durante los encuentros b├®licos entre espa├▒oles y franceses de los a├▒os 1808-1809 fue escenario de ├ísperos combates. Incluido en la "Operaci├│n Cuarteles" de los a├▒os 70, casi el 50% de su amplia superficie sigue siendo un solar entre el Paseo de M┬¬ Agust├¡n y la Plaza del Portillo.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65442100, -0.89222600, '0101000020E61000003882548A1D8DECBF66683C11C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754649500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754649500.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754649500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23918, 'Ernest Hemingway 1959', 'Foto: ├ülvaro Garc├¡a Pelayo, 1959. Tres a├▒os antes, en octubre, ya hab├¡a estado en el Coso de la Misericordia. Ahora, tres a├▒os antes de terminar con su vida, Hemingway regres├│ a la plaza de toros de Zaragoza, una tarde de agosto de sol, y "buen tiempo", a una tierra que consideraba "absolutamente igual que la m├¡a" (Illinois, Estados Unidos de Norteam├®rica). Se considera que lo acontecido esa tarde, junto con lo vivido en las de Valencia, M├ílaga, Bayona, Ciudad Real..., a Hemingway le dio material suficiente para escribir en la revista "LIFE" el art├¡culo "Verano Sangriento", una cr├│nica de la temporada toreril espa├▒ola de ese a├▒o. Fuente: Archivo Fotogr├ífico ABC. Cedida por Rafael Castillejo.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65449300, -0.89097000, '0101000020E6100000A6F27684D382ECBF003B376DC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857451254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857451254.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857451254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23920, 'Despeje de la plaza 1793', 'Despeje de la plaza, ├│leo sobre hojalata, Francisco de Goya, 1793. Colecci├│n Masaveu, Oviedo. La hasta 2014 considerada representaci├│n goyesca de la plaza de toros de Madrid, resulta ser la de Zaragoza, seg├║n estudio de Javier Mart├¡nez y Wifredo Rinc├│n publicado en el libro El coso de la Misericordia de Zaragoza (2014).', 1793, 1793, 1793, 'Siglo XIX', 'CENTRO', 41.65434800, -0.89154000, '0101000020E6100000486DE2E47E87ECBFFC19DEACC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023449854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023449854.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023449854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23925, 'Vista a├®rea 1969', 'A├®rea vista desde el Oeste hacia el centro de la ciudad. En primer plano, el Coso de la Misericordia, la Maternidad e Inclusa, el Hogar Pignatelli, la reciente Jefatura Superior de la Polic├¡a Armada, el enorme convento de las Hermanas de la Caridad de Santa Ana, y el hospital de N┬¬ S┬¬ de Gracia. En el entorno de la calle Pignatelli y Madre Rafols, el territorio militar de los cuarteles del Parque de Artiller├¡a, a la izquierda, y el Cuartel de Sangenis, derecha, a los que se sumaba el cercano de el Cid, y otros. Torres y c├║pulas van mojoneando la ret├¡cula urbana: San Pablo, Santiago el Mayor, la Seo, el Pilar... Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65327700, -0.89078800, '0101000020E61000007B6AF5D55581ECBF501DAB949ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15671223760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15671223760.webp', 'https://www.flickr.com/photos/zaragozaantigua/15671223760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23929, 'Vista a├®rea Portillo 1965', 'Vista a├®rea parcial de la zona del Portillo, centrada en el Hogar Pignatelli y el Coso de la Misericordia. Fuente visual : Fotograf├¡a a├®rea Lecar para el libro "El Ayuntamiento de Zaragoza", Colecci├│n Rafael Margal├®.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65396100, -0.89122400, '0101000020E61000003621AD31E884ECBF03EE79FEB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21694053734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21694053734.webp', 'https://www.flickr.com/photos/zaragozaantigua/21694053734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23934, 'Cuartel del Cid 1972', '"Antigua puerta de Zaragoza", ├│leo sobre cart├│n, J. Benito, 1972. Puerta de acceso principal al Cuartel de Caballer├¡a del Cid, ya abandonado. La ubicaci├│n corresponde a la actual calle de Benjam├¡n Jarn├®s 6. Fuente: www.todocoleccion.net/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65442100, -0.89222600, '0101000020E61000003882548A1D8DECBF66683C11C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25452856253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25452856253.webp', 'https://www.flickr.com/photos/zaragozaantigua/25452856253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23937, 'Coso de la Misericordia 1903', 'Imagen del interior de la antigua plaza de toros de Zaragoza, tambi├®n denominada "Coso de la Misericordia", y hasta "Coso de Pignatelli". Su primera f├íbrica, provisional, en madera, fue inaugurada en 1764, y perdur├│ hasta que en el siglo XIX se la reh├¡zo enteramente en materiales m├ís duraderos: piedra y ladrillo, adem├ís de madera. Esta es la plaza que aparece en la imagen, que como se trata de una captura fotogr├ífica francesa, fue titulada "Les ar├¿nes". Al fondo, a la izquierda, sobresale la airosa c├║pula neobizantina de la Casa de la Misericordia. Unos a├▒os m├ís tarde, en 1916, este coso ser├í reformado integralmente, d├índole el aspecto que ha llegado a nosotros. Fuente: www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26294792534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26294792534.webp', 'https://www.flickr.com/photos/zaragozaantigua/26294792534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23943, 'C├írcel de gitanas 1753', '"Indice o descripci├│n de este Plan o Fabrica nuevamente construida en la casa de Misericordia de la ciudad de Zaragoza para la Habitaci├│n de las Gitanas", realizado por el maestro de obras Onofre Graci├ín. Se trataba de una nueva construcci├│n dentro del enorme complejo de la Real Casa de Misericordia como c├írcel de gitanas, durante una de las etapas m├ís duras de represi├│n en Espa├▒a contra la etnia gitana a mediados del siglo XVIII. Considerados como pueblo "que no tiene religi├│n" y raza "malvada", fueron expulsados unos 10000 gitanos de los territorios peninsulares, y se habilitaron c├írceles para gitanas y sus hijos. Esta prisi├│n estuvo funcional para los objetivos propuestos hasta 1763, con capacidad para varios cientos de personas separadas del resto de residentes a fin de que "esta mala semilla" no pudiera "corromperlos". Su ingreso principal era desde el acceso por el Campo del Toro a la Casa de la Misericordia (a la izquierda del plano), y sus traseras eran recayentes al Campo del Sepulcro. Fuente: Archivos Estatales, Ministerio de Educaci├│n, Cultura y Deporte de Espa├▒a.', 1753, 1753, 1753, 'Siglo XIX', 'CENTRO', 41.65339600, -0.89202600, '0101000020E610000074D0251C7A8BECBF2AABE97AA2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34534841334.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34534841334.webp', 'https://www.flickr.com/photos/zaragozaantigua/34534841334/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23945, 'El Cordob├®s 1966', 'Imagen capturada en el Coso de la Misericordia, posiblemente durante la Feria del Pilar de ese a├▒o, con un primer plano ligeramente desenfocado y mirando a c├ímara del popular, heterodoxo y controvertido matador de toros palme├▒o Manuel Ben├¡tez P├®rez, alias El Cordob├®s. A su izquierda, el navarretino y altamente productivo fot├│grafo Gerardo Sancho Ramo, reci├®n cumplidos los 55 septiembres, aunando trabajo profesional y taurofilia militante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65454100, -0.89139400, '0101000020E61000005038BBB54C86ECBF1172DEFFC7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48242100981.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48242100981.webp', 'https://www.flickr.com/photos/zaragozaantigua/48242100981/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23946, 'Hospicio Provincial c.1895', 'A la original y neocl├ísica Real Casa de la Misericordia levantada a finales del siglo XVIII en las antiguas Eras del Campo del Toro, en 1867 se le a├▒adi├│ una neobizantina iglesia con dise├▒o del arquitecto Juan Antonio Atienza. En la imagen, fachada principal de la iglesia recayente al rectangular patio de acceso desde el norte. En ella se observa la alternancia de materiales constructivos, que en la parte superior culmina en ladrillo las dos torres que flanquean el ingreso y la singular c├║pula central.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65337800, -0.89076100, '0101000020E610000015AC71361D81ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50087560936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50087560936.webp', 'https://www.flickr.com/photos/zaragozaantigua/50087560936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23947, 'Vista a├®rea c.1962', 'Interesante vista a├®rea centrada en la gran estructura del Hogar Pignatelli y sus jardines de acceso, ubicado entre el Portillo, la calle de Ram├│n Pignatelli y el paseo de Mar├¡a Agust├¡n. El central patio de ingreso y la iglesia quedan flanqueados por el patio y zona de las ni├▒as y chicas, recayente a la calle de Vicente G├│mez Salvo, y el patio y zona de los ni├▒os y chicos. En primer t├®rmino, el coso de la Misericordia, el cuartel del Cid y la Maternidad. Detr├ís, el noviciado de Santa Ana, los modernos bloques de viviendas para funcionarios y los talleres de la DPZ. Hacia el fondo, instalaciones del Hospital provincial, la extensa zona de huerta de la Encarnaci├│n y el antiguo convento. Al fondo, la Puerta del Carmen y el desemboque del arbolado bulevar del paseo de Pamplona, poco antes de ser convertido en moderna autopista. Hacia la derecha y en primer t├®rmino, la triangular manzana de viviendas militares entre el paseo de Mar├¡a Agust├¡n y la calle de Anselmo Clav├®, Detr├ís, el Grupo Escolar Joaqu├¡n Costa y el edificio de la Santa Hermandad del Refugio. Entre las antiguas viviendas del paseo destaca la cl├¡nica del doctor Ricardo Horno Alcorta, esquinera con la hom├│nima calle, antes llamada de la Industria.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65327400, -0.89092200, '0101000020E6100000622EA9DA6E82ECBFDFA9807B9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51403815906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51403815906.webp', 'https://www.flickr.com/photos/zaragozaantigua/51403815906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23949, 'Hogar Pignatelli 1963', 'Imagen tomada en el patio del Hogar Pignatelli abierto a las residentes femeninas tras una decembrina nevada que aport├│ divertidas posibilidades recreativas, adem├ís de poder columpiarse. Cualquier nevada pasada siempre parece mejor.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65327400, -0.89092200, '0101000020E6100000622EA9DA6E82ECBFDFA9807B9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53644620881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53644620881.webp', 'https://www.flickr.com/photos/zaragozaantigua/53644620881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23990, 'Plaza de toros 1973', 'Aspecto de la plaza de toros de Zaragoza en 1973. Al fondo, torres y c├║pula del Hogar Pignatelli, actual sede del Gobierno de Arag├│n. Fuente: Revista El Ruedo 1.530, 1973.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18950993825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18950993825.webp', 'https://www.flickr.com/photos/zaragozaantigua/18950993825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24007, 'Plaza de Toros 1907', 'Foto: J. J├║dez. Posado de las "presidentas, asesores y representantes de la Cruz Roja, en cuyo beneficio se dio la becerrada" de los cocheros, el domingo 5 de mayo de 1907, en la Plaza de Toros de Zaragoza. En primer plano, las se├▒oritas Sanclemente, Fuertes, de Val e Iglesias, "que ricamente ataviadas con el cl├ísico pa├▒ol├│n de Manila y airosa mantilla blanca, ocuparon el sitio de honor, muy bien asesoradas por los distinguidos aficionados Manolo Velilla, Mariano Lorente, el veterano D. Baltasar Palomar y Julio Mart├¡n". Fuente: Revista "La fiesta nacional", Barcelona, 1907.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23912133684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23912133684.webp', 'https://www.flickr.com/photos/zaragozaantigua/23912133684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24118, 'Coso de la Misericordia 1916', 'Imagen capturada en el Coso de la Misericordia durante el mitin organizado por la Federaci├│n Obrera el d├¡a 16 de marzo de 1916 para tratar el grave asunto del elevado precio de las subsistencias y la crisis del trabajo, en el contexto de la larga crisis del r├®gimen de la Restauraci├│n mon├írquica agudizada en esta ocasi├│n por el impacto de la Gran Guerra. Con la presidencia de Jos├® Echegoyen, el acto cont├│ la participaci├│n de Agust├¡n Ferreruelo, Mariano Sanz y Nicol├ís Guallarte por la Sociedad de panaderos; Santos Gaspar por la Sociedad de alba├▒iles y Nicasio Domingo en nombre de los carpinteros. Este mitin matinal transcurri├│ bajo un sol de justicia entre las 10.30 y las 12.15 horas, con numerosas cr├¡ticas al Gobierno por la represi├│n de las protestas de los obreros por el precio de las subsistencias, mientras hac├¡a la vista gorda a los acaparadores y especuladores, adem├ís de seguir promoviendo la exportaci├│n de subsistencias a la Europa en guerra. Las conclusiones del acto se le hicieron llegar al gobernador civil para que las elevase al Consejo de ministros. En primer t├®rmino, vista parcial de la concurrencia al mitin mirando hacia los oradores que quedaban fuera de plano y a la izquierda. Al fondo, aspecto de la plaza con las arcadas de madera originales del coso construido en el siglo XVIII, la grader├¡a de piedra del ├║ltimo tercio del siglo XIX y la barrera y contrabarrera colocadas unos pocos a├▒os antes (1908). A finales de diciembre de 1916 comenzar├¡a la gran reforma de la plaza que al finalizar los trabajos en marzo de 1918 le dar├¡a su actual aspecto neomud├®jar.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65457300, -0.89163000, '0101000020E6100000473D44A33B88ECBF1CEC4D0CC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52780867751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52780867751.webp', 'https://www.flickr.com/photos/zaragozaantigua/52780867751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24235, 'Coso Misericordia 1956', 'Ernest Hemingway y Mary Welsh tras la barrera del Coso de la Misericordia, "attending Bull Fight in Zaragoza", si bien Ernest est├í m├ís al tanto del fot├│grafo, y bien pillo, se quita las gafas para el posado. Fuente visual: www.ernesthemingwaycollection.com/', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65453800, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFA0FEB3E6C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31839559990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31839559990.webp', 'https://www.flickr.com/photos/zaragozaantigua/31839559990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24242, 'Buffalo Bill 1950', 'Imagen capturada en el coso de la Misericordia y centrada en el personaje de Buffalo Bill, que con su espect├ículo "Wild West Show" era cabeza de cartel del Circo Americano venido a Zaragoza con motivo de las Fiestas del Pilar e instalado con gran ├®xito en el Ferial de la Gran V├¡a. El actor Edward "Joe" Gray, ex capit├ín de la Polic├¡a Montada del Canad├í y residente en Londres fue contratado para formar parte del circo por su "parecido" con el original Buffalo Bill/William Frederick Cody (1846-1917), aunque en alg├║n momento se propag├│ el bulo de que era su "descendiente y heredero". La foto recoge el momento en que el personaje exhibe una de las orejas conseguidas por el diestro Luis Miguel Domingu├¡n, que se la ofreci├│ tras una de sus faenas en la primera corrida de la feria del Pilar.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65457300, -0.89165200, '0101000020E61000003B376DC66988ECBF1CEC4D0CC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51706319544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51706319544.webp', 'https://www.flickr.com/photos/zaragozaantigua/51706319544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24384, 'Casa Hospicio c.1925', '"Fachada de la iglesia de la Real Casa de Misericordia". A la original y neocl├ísica "Real Casa de la Misericordia" levantada a finales del siglo XVIII sobre las antiguas Eras del Campo del Toro, en 1867 se le a├▒adi├│ la neobizantina iglesia, con fachada al rectangular patio de acceso desde el norte, por la calle de la Misericordia, luego de Pignatelli. Entre 1907 y 1935, este edificio fue denominado "Casa Hospicio", como espacio de beneficiencia para ni├▒os y ni├▒as exp├│sitas. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65327700, -0.89078800, '0101000020E61000007B6AF5D55581ECBF501DAB949ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22855791326.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22855791326.webp', 'https://www.flickr.com/photos/zaragozaantigua/22855791326/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25057, 'El Cordob├®s 1965', 'Ayuntamiento de Zaragoza/Gerardo Sancho. 30 de abril de 1965. Toros. 1┬¬ Corrida de la Feria de Primavera. Diestros: Paco Camino, "El Cordob├®s" y "Serranito" Manuel Ben├¡tez es uno de los toreros m├ís c├®lebres del franquismo. Aqu├¡ lo vemos rodeado de admiradores en su visita a Zaragoza.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65442900, -0.89155700, '0101000020E6100000CBA2B08BA287ECBFE9465854C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14817805410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14817805410.webp', 'https://www.flickr.com/photos/zaragozaantigua/14817805410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
